// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXQ 100005

// Define the structure for a tree node
typedef struct Node {
    int val;
    int s;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->val = val;
    node->s = 0;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**)realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to calculate the S values for each node
void calculateSValues(Node* node, int* val) {
    if (node->numChildren == 0) {
        node->s = *val;
        (*val)++;
    } else {
        for (int i = 0; i < node->numChildren; i++) {
            calculateSValues(node->children[i], val);
        }
        node->s = *val;
        (*val)++;
    }
}

// Function to find the path between two nodes
void findPath(Node* node, int target, int* path, int* pathLen) {
    if (node->val == target) {
        path[*pathLen] = node->val;
        (*pathLen)++;
        return;
    }
    for (int i = 0; i < node->numChildren; i++) {
        findPath(node->children[i], target, path, pathLen);
        if (*pathLen > 0) {
            path[*pathLen] = node->val;
            (*pathLen)++;
            return;
        }
    }
}

// Function to count the number of inversions in the S values along the path
int countInversions(int* path, int* sValues, int pathLen) {
    int inversions = 0;
    for (int i = 0; i < pathLen; i++) {
        for (int j = i + 1; j < pathLen; j++) {
            if (sValues[path[i]] > sValues[path[j]]) {
                inversions++;
            }
        }
    }
    return inversions;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        Node** nodes = (Node**)malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addChild(nodes[u - 1], nodes[v - 1]);
            addChild(nodes[v - 1], nodes[u - 1]);
        }
        int val = 1;
        calculateSValues(nodes[0], &val);
        int* sValues = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            sValues[i] = nodes[i]->s;
        }
        for (int q = 0; q < Q; q++) {
            int u, v;
            scanf("%d %d", &u, &v);
            int* path = (int*)malloc(N * sizeof(int));
            int pathLen = 0;
            findPath(nodes[0], u, path, &pathLen);
            findPath(nodes[0], v, path, &pathLen);
            int inversions = countInversions(path, sValues, pathLen);
            printf("%d\n", inversions);
            free(path);
        }
        free(sValues);
        for (int i = 0; i < N; i++) {
            free(nodes[i]->children);
            free(nodes[i]);
        }
        free(nodes);
    }
    return 0;
}

