#include <iostream>
#include <vector>
using namespace std;

// Define the structure for a tree node
struct Node {
    int val;
    int s;
    vector<Node*> children;
};

// Function to create a new node
Node* createNode(int val) {
    Node* node = new Node;
    node->val = val;
    node->s = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->children.push_back(child);
}

// Function to calculate the S values for each node
void calculateSValues(Node* node, int& val) {
    if (node->children.empty()) {
        node->s = val;
        val++;
    } else {
        for (Node* child : node->children) {
            calculateSValues(child, val);
        }
        node->s = val;
        val++;
    }
}

// Function to find the path between two nodes
void findPath(Node* node, int target, vector<int>& path) {
    if (node->val == target) {
        path.push_back(node->val);
        return;
    }
    for (Node* child : node->children) {
        findPath(child, target, path);
        if (!path.empty()) {
            path.push_back(node->val);
            return;
        }
    }
}

// Function to count the number of inversions in the S values along the path
int countInversions(vector<int>& path, vector<int>& sValues) {
    int inversions = 0;
    for (int i = 0; i < path.size(); i++) {
        for (int j = i + 1; j < path.size(); j++) {
            if (sValues[path[i] - 1] > sValues[path[j] - 1]) {
                inversions++;
            }
        }
    }
    return inversions;
}

int main() {
    int T;
    cin >> T;
    for (int t = 0; t < T; t++) {
        int N, Q;
        cin >> N >> Q;
        Node** nodes = new Node*[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            cin >> u >> v;
            addChild(nodes[u - 1], nodes[v - 1]);
            addChild(nodes[v - 1], nodes[u - 1]);
        }
        int val = 1;
        calculateSValues(nodes[0], val);
        vector<int> sValues(N);
        for (int i = 0; i < N; i++) {
            sValues[i] = nodes[i]->s;
        }
        for (int q = 0; q < Q; q++) {
            int u, v;
            cin >> u >> v;
            vector<int> path;
            findPath(nodes[0], u, path);
            findPath(nodes[0], v, path);
            int inversions = countInversions(path, sValues);
            cout << inversions << endl;
        }
        for (int i = 0; i < N; i++) {
            delete nodes[i];
        }
        delete[] nodes;
    }
    return 0;
}

