import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int val;
        int s;
        ArrayList<Node> children;

        public Node(int val) {
            this.val = val;
            this.s = 0;
            this.children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    public static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    // Function to calculate the S values for each node
    public static void calculateSValues(Node node, int[] val) {
        if (node.children.isEmpty()) {
            node.s = val[0];
            val[0]++;
        } else {
            for (Node child : node.children) {
                calculateSValues(child, val);
            }
            node.s = val[0];
            val[0]++;
        }
    }

    // Function to find the path between two nodes
    public static void findPath(Node node, int target, ArrayList<Integer> path) {
        if (node.val == target) {
            path.add(node.val);
            return;
        }
        for (Node child : node.children) {
            findPath(child, target, path);
            if (!path.isEmpty()) {
                path.add(node.val);
                return;
            }
        }
    }

    // Function to count the number of inversions in the S values along the path
    public static int countInversions(ArrayList<Integer> path, int[] sValues) {
        int inversions = 0;
        for (int i = 0; i < path.size(); i++) {
            for (int j = i + 1; j < path.size(); j++) {
                if (sValues[path.get(i) - 1] > sValues[path.get(j) - 1]) {
                    inversions++;
                }
            }
        }
        return inversions;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            int Q = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node(i + 1);
            }
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                addChild(nodes[u - 1], nodes[v - 1]);
                addChild(nodes[v - 1], nodes[u - 1]);
            }
            int[] val = new int[] {1};
            calculateSValues(nodes[0], val);
            int[] sValues = new int[N];
            for (int i = 0; i < N; i++) {
                sValues[i] = nodes[i].s;
            }
            for (int q = 0; q < Q; q++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                ArrayList<Integer> path = new ArrayList<>();
                findPath(nodes[0], u, path);
                findPath(nodes[0], v, path);
                int inversions = countInversions(path, sValues);
                System.out.println(inversions);
            }
        }
    }
}

